// bslmt_barrier.cpp                                                  -*-C++-*-
#include <bslmt_barrier.h>

#include <bsls_ident.h>
BSLS_IDENT_RCSID(bslmt_barrier_cpp,"$Id$ $CSID$")

#include <bslmt_lockguard.h>
#include <bslmt_threadutil.h> // for yield

#include <bsls_assert.h>

namespace BloombergLP {

bslmt::Barrier::~Barrier()
{
    while (1) {
        {
            LockGuard<Mutex> lock(&d_mutex);
            if (0 == d_numPending) break;
        }
        ThreadUtil::yield();
    }

    BSLS_ASSERT(0 == d_numWaiting);
}

void bslmt::Barrier::arrive()
{
    LockGuard<Mutex> lock(&d_mutex);
    if (++d_numArrived == d_numArrivals) {
        ++d_sigCount;
        d_numPending += d_numWaiting;
        d_numArrived = 0;
        d_numWaiting = 0;
        d_cond.broadcast();
    }
}

int bslmt::Barrier::timedWait(const bsls::TimeInterval& absTime)
{
    LockGuard<Mutex> lock(&d_mutex);
    int prevSigCount = d_sigCount;
    ++d_numWaiting;
    if (++d_numArrived == d_numArrivals) {
        ++d_sigCount;
        d_numPending += d_numWaiting - 1;
        d_numArrived = 0;
        d_numWaiting = 0;
        d_cond.broadcast();
    }
    else {
        while (d_sigCount == prevSigCount) {
            if (d_cond.timedWait(&d_mutex, absTime) &&
                d_sigCount == prevSigCount) {
                --d_numArrived;
                --d_numWaiting;
                return e_TIMED_OUT;                                   // RETURN
            }
        }
        --d_numPending;
    }
    return 0;
}

void bslmt::Barrier::wait()
{
    LockGuard<Mutex> lock(&d_mutex);
    int sigCount = d_sigCount;
    ++d_numWaiting;
    if (++d_numArrived == d_numArrivals) {
        ++d_sigCount;
        d_numPending += d_numWaiting - 1;
        d_numArrived = 0;
        d_numWaiting = 0;
        d_cond.broadcast();
    }
    else {
        while (d_sigCount == sigCount) {
            d_cond.wait(&d_mutex);
        }
        --d_numPending;
    }
}

